INSERT INTO "applications" ("id", "user_id", "course_id", "full_name", "email", "phone", "professional_background", "status", "admin_notes", "created_at", "updated_at") VALUES (6, 7, 2, 'Lucy Patel', 'lucy.patel@carehome.co.uk', '07700 900 666', 'Senior carer supporting children with neurological conditions.', 'rejected', 'Rejected — does not meet the minimum clinical experience requirement.', '2026-05-27 14:50:53', '2026-05-27 14:50:53');
INSERT INTO "assessment_submissions" ("id", "assessment_id", "user_id", "answers", "submitted_at", "started_at", "score", "marker_notes", "marked_at", "created_at", "updated_at", "question_marks") VALUES (1, 1, 2, '[{"question_index":0,"answer":"A patient in hospital is under medical authority and follows clinical protocols. A person in the community retains autonomy, choice, and is supported in their own home environment."},{"question_index":1,"answer":"Airway, Breathing, Circulation, Disability, Exposure \u2014 in that order using the ABCDE approach."},{"question_index":2,"answer":"A tracheostomy bypasses the nose and mouth which normally warm, humidify and filter air. Without this, secretions dry out and form plugs."},{"question_index":3,"answer":"A smaller tube can pass through a partially closed stoma, maintaining the airway until a correctly sized tube is available."},{"question_index":4,"answer":"Invasive ventilation uses an artificial airway such as a tracheostomy. Non-invasive uses a mask, e.g. BIPAP or CPAP."},{"question_index":5,"answer":"Air may be escaping from a loose circuit connection or cuff leak. I would check all connections and the cuff pressure."},{"question_index":6,"answer":"A blockage in the circuit or airway, e.g. mucus plug. I would suction the airway and check the circuit for kinks."},{"question_index":7,"answer":"BIPAP delivers two pressure levels \u2014 inspiratory and expiratory. CPAP delivers one continuous pressure."},{"question_index":8,"answer":"BIPAP: IPAP 14, EPAP 6. CPAP: single pressure e.g. 8 cmH2O."},{"question_index":9,"answer":"Enteral feeding is the delivery of nutrition directly into the gastrointestinal tract via a tube."},{"question_index":10,"answer":"Inability to swallow safely, neurological conditions, failure to thrive, or post-surgical recovery."},{"question_index":11,"answer":"NG tube for short-term, PEG for long-term gastric feeding, PEJ for post-pyloric feeding when gastric feeding is not tolerated."},{"question_index":12,"answer":"PEG sits in the stomach, PEJ in the jejunum. PEG allows bolus feeding, PEJ requires continuous pump feeding."},{"question_index":13,"answer":"The stomach can accommodate bolus volumes and has a reservoir function. The small bowel cannot tolerate large volumes rapidly."},{"question_index":14,"answer":"Recurrent chest infections, cyanosis, desaturations during feeding, or wet\/gurgly voice without coughing."},{"question_index":15,"answer":"Abnormal, excessive electrical discharges between neurons causing synchronised firing across brain regions."},{"question_index":16,"answer":"Most seizures self-terminate within 5 minutes. Early medication carries risks of respiratory depression without clear benefit."},{"question_index":17,"answer":"Buccal administration allows rapid absorption through the oral mucosa, bypassing the GI tract and acting faster than oral ingestion."},{"question_index":18,"answer":"500 \u00f7 250 \u00d7 1 = 2 tablets."},{"question_index":19,"answer":"300 \u00f7 100 \u00d7 5 = 15 mL."},{"question_index":20,"answer":"12.5 \u00f7 10 \u00d7 2 = 2.5 mL. Using 2 mL would underdose the patient by 0.5 mL."},{"question_index":21,"answer":"1000 \u00f7 500 \u00d7 1 = 2 tablets."},{"question_index":22,"answer":"180 \u00f7 250 \u00d7 5 = 3.6 mL."},{"question_index":23,"answer":"Situation: I''m calling about [patient name] who is deteriorating. Background: They have [condition] and their baseline is [X]. Assessment: They are currently [grey, not breathing normally]. Recommendation: I need an ambulance immediately."}]', '2026-05-27 12:50:53', '2026-05-27 11:50:53', 88, 'Excellent responses throughout. Strong clinical reasoning demonstrated.', '2026-05-27 13:50:53', '2026-05-27 14:50:53', '2026-05-27 14:50:53', '[{"question_index":0,"awarded":4},{"question_index":1,"awarded":4},{"question_index":2,"awarded":4},{"question_index":3,"awarded":4},{"question_index":4,"awarded":4},{"question_index":5,"awarded":4},{"question_index":6,"awarded":4},{"question_index":7,"awarded":4},{"question_index":8,"awarded":4},{"question_index":9,"awarded":3},{"question_index":10,"awarded":4},{"question_index":11,"awarded":4},{"question_index":12,"awarded":4},{"question_index":13,"awarded":4},{"question_index":14,"awarded":4},{"question_index":15,"awarded":4},{"question_index":16,"awarded":4},{"question_index":17,"awarded":4},{"question_index":18,"awarded":3},{"question_index":19,"awarded":3},{"question_index":20,"awarded":3},{"question_index":21,"awarded":3},{"question_index":22,"awarded":3},{"question_index":23,"awarded":4}]');
INSERT INTO "assessment_submissions" ("id", "assessment_id", "user_id", "answers", "submitted_at", "started_at", "score", "marker_notes", "marked_at", "created_at", "updated_at", "question_marks") VALUES (2, 1, 3, '[{"question_index":0,"answer":"In hospital, the patient is in a clinical environment with immediate medical support. In the community, the person is at home and care must be adapted to their environment and wishes."},{"question_index":1,"answer":"ABCDE \u2014 Airway first, then Breathing, Circulation, Disability, Exposure."},{"question_index":2,"answer":"Normal breathing through the nose warms and humidifies air. A tracheostomy bypasses this, causing secretions to thicken and form plugs."},{"question_index":3,"answer":"The stoma may begin to close. A smaller tube can still be inserted to keep the airway patent while waiting for the correct size."},{"question_index":4,"answer":"Invasive: ventilation via tracheostomy or ETT. Non-invasive: BIPAP or CPAP via mask."},{"question_index":5,"answer":"Possible cuff deflation or loose connection. Check and tighten all connections, check cuff pressure."},{"question_index":6,"answer":"Secretion build-up or kinked tubing. Suction the patient and check the circuit."},{"question_index":7,"answer":"CPAP provides one constant pressure. BIPAP provides two \u2014 a higher pressure on inspiration and lower on expiration."},{"question_index":8,"answer":"CPAP: 10 cmH2O. BIPAP: IPAP 16, EPAP 8."},{"question_index":9,"answer":"Delivering nutrition via a tube into the stomach or intestine."},{"question_index":10,"answer":"Dysphagia, neurological impairment, malnutrition, or inability to meet nutritional needs orally."},{"question_index":11,"answer":"NG: short-term, nasogastric. PEG: long-term, gastric. PEJ: post-pyloric, for those who cannot tolerate gastric feeding."},{"question_index":12,"answer":"PEG is in the stomach and allows bolus feeding. PEJ is in the jejunum and requires continuous feeding."},{"question_index":13,"answer":"The stomach acts as a reservoir and can handle bolus volumes. The jejunum cannot \u2014 it requires slow continuous delivery."},{"question_index":14,"answer":"Chest infections, desaturations, or changes in breathing pattern during or after feeding without coughing."},{"question_index":15,"answer":"Uncontrolled electrical activity in the brain causing neurons to fire abnormally and synchronously."},{"question_index":16,"answer":"Most seizures stop on their own within 5 minutes. Giving medication too early increases the risk of respiratory depression."},{"question_index":17,"answer":"The buccal mucosa has a rich blood supply allowing rapid absorption. Oral ingestion would be too slow and unreliable during a seizure."},{"question_index":18,"answer":"500 \u00f7 250 \u00d7 1 = 2 tablets."},{"question_index":19,"answer":"300 \u00f7 100 \u00d7 5 = 15 mL."},{"question_index":20,"answer":"The correct dose is 2.5 mL. Using 2 mL gives only 10 mg, which is 2.5 mg short of the prescribed dose."},{"question_index":21,"answer":"1000 \u00f7 500 = 2 tablets."},{"question_index":22,"answer":"180 \u00f7 250 \u00d7 5 = 3.6 mL."},{"question_index":23,"answer":"S: I''m calling about [name], who is unresponsive. B: They have a tracheostomy and are ventilator-dependent. A: They are not breathing and have no pulse. R: Please send an ambulance immediately to [address]."}]', '2026-05-27 12:50:53', '2026-05-27 11:50:53', 74, 'Good overall. Some dosage calculation answers could be more detailed.', '2026-05-27 13:50:53', '2026-05-27 14:50:53', '2026-05-27 14:50:53', '[{"question_index":0,"awarded":3},{"question_index":1,"awarded":4},{"question_index":2,"awarded":3},{"question_index":3,"awarded":3},{"question_index":4,"awarded":4},{"question_index":5,"awarded":3},{"question_index":6,"awarded":3},{"question_index":7,"awarded":3},{"question_index":8,"awarded":3},{"question_index":9,"awarded":2},{"question_index":10,"awarded":3},{"question_index":11,"awarded":4},{"question_index":12,"awarded":3},{"question_index":13,"awarded":3},{"question_index":14,"awarded":3},{"question_index":15,"awarded":3},{"question_index":16,"awarded":3},{"question_index":17,"awarded":3},{"question_index":18,"awarded":2},{"question_index":19,"awarded":2},{"question_index":20,"awarded":2},{"question_index":21,"awarded":2},{"question_index":22,"awarded":2},{"question_index":23,"awarded":3}]');
INSERT INTO "assessment_submissions" ("id", "assessment_id", "user_id", "answers", "submitted_at", "started_at", "score", "marker_notes", "marked_at", "created_at", "updated_at", "question_marks") VALUES (3, 1, 4, '[{"question_index":0,"answer":"A hospital patient is in an acute setting with clinical oversight. A community person is in their own home and care is person-centred around their life."},{"question_index":1,"answer":"Airway, Breathing, Circulation, Disability, Exposure."},{"question_index":2,"answer":"The nose filters and humidifies air. A tracheostomy bypasses this so secretions dry and thicken into plugs."},{"question_index":3,"answer":"A smaller tube can fit through a narrowing stoma to maintain the airway temporarily."},{"question_index":4,"answer":"Invasive uses a tube in the airway. Non-invasive uses a mask. Examples: tracheostomy ventilation vs CPAP."},{"question_index":5,"answer":"Air escaping from a loose connection or deflated cuff. Check all connections and re-inflate the cuff."},{"question_index":6,"answer":"Blocked airway or kinked tubing. Suction and check the circuit."},{"question_index":7,"answer":"BIPAP has two pressure settings. CPAP has one."},{"question_index":8,"answer":"BIPAP: IPAP 12, EPAP 5. CPAP: 8 cmH2O."},{"question_index":9,"answer":"Feeding through a tube into the gut."},{"question_index":10,"answer":"Swallowing difficulties, neurological conditions, or failure to thrive."},{"question_index":11,"answer":"NG for short-term, PEG for long-term stomach feeding, PEJ for small bowel feeding."},{"question_index":12,"answer":"PEG is in the stomach, PEJ in the small bowel. PEG allows bolus, PEJ needs continuous feeding."},{"question_index":13,"answer":"The stomach can hold large volumes. The small bowel cannot tolerate rapid large volumes."},{"question_index":14,"answer":"Chest infections, wet breathing, or desaturations without coughing."},{"question_index":15,"answer":"Abnormal electrical discharges in the brain."},{"question_index":16,"answer":"Most seizures stop within 5 minutes naturally. Early medication risks respiratory depression."},{"question_index":17,"answer":"Faster absorption through the cheek lining compared to swallowing."},{"question_index":18,"answer":"2 tablets."},{"question_index":19,"answer":"15 mL."},{"question_index":20,"answer":"The correct dose is 2.5 mL. 2 mL only delivers 10 mg, underdosing by 2.5 mg."},{"question_index":21,"answer":"2 tablets."},{"question_index":22,"answer":"3.6 mL."},{"question_index":23,"answer":"S: [Patient] is deteriorating. B: History of [condition]. A: Currently grey and unresponsive. R: Need emergency ambulance now."}]', '2026-05-27 12:50:53', '2026-05-27 11:50:53', NULL, NULL, NULL, '2026-05-27 14:50:53', '2026-05-27 14:50:53', NULL);
INSERT INTO "assessments" ("id", "course_id", "title", "instructions", "questions", "time_limit_minutes", "is_active", "created_at", "updated_at") VALUES (1, 2, 'Post-Training Assessment', 'Please answer all questions in the spaces provided below. Completion of this assessment is required to receive your certificate. Answer in your own words — there are no trick questions. Your responses will be reviewed by a trainer.', '[{"question":"Person versus Patient: What distinguishes a \"patient\" within a hospital from a \"person\" in the community?","type":"text","marks":4,"optional":false},{"question":"Order of Clinical Assessment: If your patient presents with a \"grey\" appearance, what is the precise sequence in which you should assess them?","type":"text","marks":5,"optional":false},{"question":"Airway \u2013 Mucus Plugs: Why does a tracheostomy lead to the formation of \"mucus plugs,\" whereas this is not an issue with normal nasal breathing?","type":"text","marks":4,"optional":false},{"question":"Emergency \u2013 The Emergency Box: When the tube has been removed and cannot be reinserted, why is having access to a smaller-sized tube advantageous?","type":"text","marks":4,"optional":false},{"question":"Ventilation: What is the difference between invasive and non-invasive ventilation? Give examples of each.","type":"text","marks":5,"optional":false},{"question":"Low Pressure Alarms: If the ventilator alarms for \"Low Pressure\" and the circuit remains connected, where might the air be escaping? What would you do?","type":"text","marks":4,"optional":false},{"question":"High Pressure Alarms: If the ventilator alarms for \"High Pressure\" and the circuit remains connected, where might the blockage or issue be occurring? What would you do?","type":"text","marks":4,"optional":false},{"question":"BIPAP vs. CPAP: What is the difference between BIPAP and CPAP mode?","type":"text","marks":4,"optional":false},{"question":"BIPAP vs. CPAP: What are the differences between BIPAP and CPAP settings? Provide examples.","type":"text","marks":4,"optional":false},{"question":"Gastrointestinal \u2013 PEG vs. PEJ: What is enteral feeding?","type":"text","marks":3,"optional":false},{"question":"Gastrointestinal \u2013 PEG vs. PEJ: What are the indications for enteral feeding?","type":"text","marks":4,"optional":false},{"question":"Gastrointestinal \u2013 PEG vs. PEJ: Name the different types of enteral feeding and state the indications for each method.","type":"text","marks":5,"optional":false},{"question":"Gastrointestinal \u2013 PEG vs. PEJ: What are the differences between the enteral feeding methods?","type":"text","marks":4,"optional":false},{"question":"Gastrointestinal \u2013 PEG vs. PEJ: Why is it permissible to bolus feed into the stomach (via PEG) but contraindicated for the small bowel (via PEJ)?","type":"text","marks":4,"optional":false},{"question":"Dysphagia \u2013 Silent Aspiration: How can \"Silent Aspiration\" be identified in a patient lacking a cough reflex?","type":"text","marks":4,"optional":false},{"question":"Neurology \u2013 Seizures\/Epilepsy: What electrical phenomena occur in the brain during a seizure?","type":"text","marks":4,"optional":false},{"question":"Neurology \u2013 Seizures\/Epilepsy: What is the rationale for waiting five minutes before administering rescue medications?","type":"text","marks":4,"optional":false},{"question":"Rescue Medications \u2013 Buccal Administration: What is the clinical reasoning behind administering Midazolam via the buccal route instead of oral ingestion?","type":"text","marks":4,"optional":false},{"question":"Dosage Calculations \u2013 The Universal Formula (D \u00f7 H \u00d7 Q = X):\n\nScenario 1: A doctor prescribes 500 mg of Metformin. You find tablets labelled 250 mg.\nD: 500 mg | H: 250 mg | Q: 1 tablet\n\nUsing the formula, calculate how many tablets to administer and show your working.","type":"text","marks":3,"optional":false},{"question":"Dosage Calculations \u2013 The Universal Formula (D \u00f7 H \u00d7 Q = X):\n\nScenario 2: A patient requires 300 mg of Ibuprofen liquid. The bottle states 100 mg per 5 mL.\nD: 300 mg | H: 100 mg | Q: 5 mL\n\nUsing the formula, calculate the volume to administer and show your working.","type":"text","marks":3,"optional":false},{"question":"Dosage Calculations \u2013 The 2 mL Issue: For a dose of 12.5 mg and a solution concentration of 10 mg\/2 mL, why is using 2 mL insufficient for accurate clinical dosing?","type":"text","marks":3,"optional":false},{"question":"Dosage Calculations: Calculate how many 500 mg tablets are required for a 1 g Paracetamol dose. Show your working.","type":"text","marks":3,"optional":false},{"question":"Dosage Calculations: Determine the required volume of a 250 mg\/5 mL Paracetamol solution for a 180 mg dose. Show your working.","type":"text","marks":3,"optional":false},{"question":"SBAR Protocol \u2013 Emergency Calls: How can you effectively communicate a patient crisis to a 999 operator using only four sentences? Write out your four sentences.","type":"text","marks":4,"optional":false}]', 120, 1, '2026-05-27 14:50:50', '2026-05-27 14:50:50');
