INSERT INTO "courses" ("id", "title", "slug", "description", "overview", "learning_objectives", "curriculum", "accreditation", "duration", "location", "price", "is_active", "created_at", "updated_at") VALUES (1, 'Paediatric Complex Care: A Comprehensive 3-Day Clinical Course', 'paediatric-complex-care-3-day', 'An intensive, evidence-based programme covering all aspects of paediatric complex care. Designed for nurses, therapists, and allied health professionals working with children with complex health needs.', 'This three-day clinical course provides healthcare professionals with the specialist knowledge, practical skills, and clinical confidence required to deliver outstanding care to children and young people with complex health needs. Delivered by experienced paediatric clinicians, the programme combines evidence-based theory with hands-on practical sessions and real-world case studies. Participants will leave with immediately applicable skills and a comprehensive understanding of best practice in paediatric complex care.', '["Understand the physiological and developmental needs of children with complex health conditions","Demonstrate competence in the assessment and management of common paediatric complex care presentations","Apply evidence-based frameworks to clinical decision-making in complex care settings","Effectively communicate with children, families, and multidisciplinary teams","Identify safeguarding considerations specific to children with complex needs","Develop and implement individualised care plans for children with complex health needs","Recognise and respond to clinical deterioration in paediatric complex care patients","Understand the legal and ethical frameworks governing paediatric complex care"]', '[{"day":"Day 1","title":"Foundations of Paediatric Complex Care","topics":["Introduction to paediatric complex care: definitions and scope","Child development and the impact of complex health conditions","Anatomy and physiology relevant to complex care presentations","Assessment frameworks: ABCDE and paediatric-specific tools","Respiratory management: tracheostomy care and ventilator support","Enteral feeding: NG, NJ, and gastrostomy management","Practical skills stations: airway management and feeding tube care"]},{"day":"Day 2","title":"Clinical Management & Specialist Interventions","topics":["Neurological conditions in paediatric complex care","Epilepsy management and emergency protocols","Medication management and administration in complex care","Pain assessment and management in non-verbal children","Skin integrity and pressure area care","Moving and handling: specialist equipment and techniques","Case study workshops: applying clinical knowledge to practice"]},{"day":"Day 3","title":"Holistic Care, Safeguarding & Professional Practice","topics":["Family-centred care: working in partnership with parents and carers","Safeguarding children with complex needs: recognition and response","Transition planning: from paediatric to adult services","Mental health and wellbeing of children with complex needs","Ethical and legal frameworks in paediatric complex care","Documentation, record-keeping, and professional accountability","Simulation scenarios and competency assessment","Course summary, reflection, and next steps"]}]', 'CPD Accredited — 21 Hours', '3 Days', 'UK Venues', 595, 1, '2026-05-27 14:50:50', '2026-05-27 14:50:50');
INSERT INTO "courses" ("id", "title", "slug", "description", "overview", "learning_objectives", "curriculum", "accreditation", "duration", "location", "price", "is_active", "created_at", "updated_at") VALUES (2, 'Three-Day Complex Care Training for Health Care Professionals in the Community', 'three-day-complex-care-training', 'A comprehensive three-day training programme covering complex care skills for health care professionals working in community settings.', 'This programme equips community health care professionals with the knowledge and practical skills to manage complex care needs including tracheostomy care, ventilation, enteral feeding, neurological emergencies, dysphagia, and safe medication administration.', '["Understand the distinction between hospital patient care and community person-centred care","Perform a structured ABCDE clinical assessment","Manage tracheostomy care and associated emergencies","Understand invasive and non-invasive ventilation and respond to ventilator alarms","Differentiate between BIPAP and CPAP modes and settings","Understand enteral feeding methods including PEG and PEJ","Identify silent aspiration in patients without a cough reflex","Recognise and respond to seizures and epilepsy","Administer buccal Midazolam safely","Apply the universal drug dosage calculation formula accurately","Communicate effectively using the SBAR protocol in emergencies"]', '[{"day":"Day 1","title":"Person-Centred Care, Clinical Assessment & Airway Management","topics":["Person versus Patient \u2014 community care philosophy","Order of clinical assessment (ABCDE approach)","Tracheostomy care and mucus plug prevention","Emergency box and tube management"]},{"day":"Day 2","title":"Ventilation, Gastrointestinal Care & Dysphagia","topics":["Invasive vs non-invasive ventilation","Low and high pressure ventilator alarms","BIPAP vs CPAP modes and settings","Enteral feeding \u2014 PEG vs PEJ","Silent aspiration and dysphagia management"]},{"day":"Day 3","title":"Neurology, Medications & Emergency Communication","topics":["Seizures and epilepsy management","Rescue medications \u2014 buccal Midazolam","Drug dosage calculations (universal formula)","SBAR protocol for emergency calls"]}]', 'Certificate of Completion issued upon passing the post-training assessment.', '3 days', 'Community / On-site', 0, 1, '2026-05-27 14:50:50', '2026-05-27 14:50:50');
