INSERT INTO "page_contents" ("id", "page", "key", "label", "type", "value", "created_at", "updated_at") VALUES (1, 'home', 'hero.headline', 'Hero — Headline', 'text', 'Specialist Care
INSERT INTO "page_contents" ("id", "page", "key", "label", "type", "value", "created_at", "updated_at") VALUES (2, 'home', 'hero.subtext', 'Hero — Subtext', 'textarea', 'With over 10 years of experience, we provide specialist clinical training to healthcare professionals supporting children and young people with complex care needs, learning disabilities, and neurological conditions across the UK.', '2026-05-27 14:50:50', '2026-05-27 14:50:50');
INSERT INTO "page_contents" ("id", "page", "key", "label", "type", "value", "created_at", "updated_at") VALUES (3, 'home', 'hero.cta_label', 'Hero — CTA Button Label', 'text', 'Find out more', '2026-05-27 14:50:50', '2026-05-27 14:50:50');
