INSERT INTO "page_contents" ("id", "page", "key", "label", "type", "value", "created_at", "updated_at") VALUES (7, 'home', 'services.badge', 'Services — Badge Text', 'text', 'What We Cover', '2026-05-27 14:50:50', '2026-05-27 14:50:50');
INSERT INTO "page_contents" ("id", "page", "key", "label", "type", "value", "created_at", "updated_at") VALUES (8, 'home', 'services.headline', 'Services — Headline', 'text', 'Specialist training across all areas of complex care', '2026-05-27 14:50:50', '2026-05-27 14:50:50');
INSERT INTO "page_contents" ("id", "page", "key", "label", "type", "value", "created_at", "updated_at") VALUES (9, 'home', 'services.subtext', 'Services — Subtext', 'textarea', 'Our programmes cover the full spectrum of paediatric complex care, from clinical skills to safeguarding and family-centred practice.', '2026-05-27 14:50:50', '2026-05-27 14:50:50');
INSERT INTO "page_contents" ("id", "page", "key", "label", "type", "value", "created_at", "updated_at") VALUES (10, 'home', 'services.items', 'Services — Cards (JSON)', 'json', '[{"title":"Paediatric Complex Care","description":"Specialist training for professionals supporting children with complex, long-term health conditions requiring nurse-led, multi-disciplinary care.","href":"\/courses\/paediatric-complex-care-3-day"},{"title":"Neurological Conditions","description":"Comprehensive modules covering acquired brain injury, epilepsy management, and neurological assessment in paediatric settings.","href":"\/courses"},{"title":"Respiratory & Airway","description":"Hands-on training in tracheostomy care, ventilator management, and emergency airway protocols for complex care environments.","href":"\/courses"},{"title":"Enteral Feeding","description":"Evidence-based training in NG, NJ, and gastrostomy management, including troubleshooting and family education.","href":"\/courses"},{"title":"Family-Centred Care","description":"Developing skills to work in genuine partnership with families, carers, and multidisciplinary teams around the child.","href":"\/courses"},{"title":"Safeguarding","description":"Recognising and responding to safeguarding concerns specific to children with complex health needs and disabilities.","href":"\/courses"}]', '2026-05-27 14:50:50', '2026-05-27 14:50:50');
INSERT INTO "page_contents" ("id", "page", "key", "label", "type", "value", "created_at", "updated_at") VALUES (11, 'home', 'why.headline', 'Why Choose Us — Headline', 'text', 'The MMAB Consulting Difference', '2026-05-27 14:50:50', '2026-05-27 14:50:50');
INSERT INTO "page_contents" ("id", "page", "key", "label", "type", "value", "created_at", "updated_at") VALUES (12, 'home', 'why.subtext', 'Why Choose Us — Subtext', 'textarea', 'We are a specialist healthcare training consultancy with a single focus: equipping professionals to deliver outstanding care to children with complex needs. Every aspect of our programmes reflects that commitment.', '2026-05-27 14:50:50', '2026-05-27 14:50:50');
INSERT INTO "page_contents" ("id", "page", "key", "label", "type", "value", "created_at", "updated_at") VALUES (13, 'home', 'why.points', 'Why Choose Us — Points (JSON)', 'json', '[{"title":"Nurse-Led Curriculum","description":"Every programme is designed and delivered by experienced paediatric complex care nurses."},{"title":"CPD Accredited","description":"21 hours of accredited CPD per programme, recognised nationally across the UK."},{"title":"Regulatory Compliance","description":"Content aligned with CQC standards, NMC guidelines, and current national frameworks."},{"title":"Personalised Support","description":"Small group sizes and dedicated facilitators ensure every learner gets the attention they need."},{"title":"Proven Outcomes","description":"Measurable competency improvements tracked through pre- and post-course assessments."},{"title":"Comprehensive Resources","description":"Full digital course materials, reference guides, and post-course access to learning resources."}]', '2026-05-27 14:50:50', '2026-05-27 14:50:50');
INSERT INTO "page_contents" ("id", "page", "key", "label", "type", "value", "created_at", "updated_at") VALUES (14, 'home', 'testimonials.headline', 'Testimonials — Headline', 'text', 'What healthcare professionals say', '2026-05-27 14:50:50', '2026-05-27 14:50:50');
INSERT INTO "page_contents" ("id", "page", "key", "label", "type", "value", "created_at", "updated_at") VALUES (15, 'home', 'testimonials.items', 'Testimonials — Items (JSON)', 'json', '[{"quote":"The 3-day course completely transformed how I approach complex care. The clinical scenarios were incredibly realistic and the facilitators were outstanding. I left feeling genuinely confident.","name":"Sarah Mitchell","role":"Paediatric Community Nurse, NHS Trust","rating":5},{"quote":"I have attended many CPD courses over my career, but MMAB stands out for the quality of content and the practical focus. The safeguarding module alone was worth the entire programme.","name":"James Okafor","role":"Complex Care Coordinator, Independent Provider","rating":5},{"quote":"Our whole team attended and the impact on our practice has been immediate. The family-centred care sessions gave us a shared language that has genuinely improved our relationships with families.","name":"Dr. Priya Sharma","role":"Clinical Lead, Paediatric Complex Care","rating":5}]', '2026-05-27 14:50:50', '2026-05-27 14:50:50');
INSERT INTO "page_contents" ("id", "page", "key", "label", "type", "value", "created_at", "updated_at") VALUES (16, 'home', 'video.title', 'Video Section — Title', 'text', 'See how we make a difference', '2026-05-27 14:50:50', '2026-05-27 14:50:50');
INSERT INTO "page_contents" ("id", "page", "key", "label", "type", "value", "created_at", "updated_at") VALUES (17, 'home', 'video.subtitle', 'Video Section — Subtitle', 'textarea', 'Watch how MMAB Consulting is transforming paediatric complex care training across the UK.', '2026-05-27 14:50:50', '2026-05-27 14:50:50');
INSERT INTO "page_contents" ("id", "page", "key", "label", "type", "value", "created_at", "updated_at") VALUES (18, 'home', 'cases.headline', 'Case Studies — Headline', 'text', 'How we''ve helped professionals and teams', '2026-05-27 14:50:50', '2026-05-27 14:50:50');
INSERT INTO "page_contents" ("id", "page", "key", "label", "type", "value", "created_at", "updated_at") VALUES (19, 'home', 'cases.items', 'Case Studies — Items (JSON)', 'json', '[{"tag":"Clinical Impact","title":"Improving tracheostomy safety across a community team","story":"A community nursing team of 14 attended the respiratory module following a series of near-miss incidents. Post-training audit showed a 94% improvement in protocol adherence and zero incidents in the 6 months following.","outcome":"94% improvement in protocol adherence"},{"tag":"Professional Development","title":"Building confidence in newly qualified nurses","story":"A cohort of newly qualified nurses reported significant anxiety around complex care placements. Following the 3-day programme, 100% reported feeling \"confident\" or \"very confident\" in their clinical decision-making.","outcome":"100% reported increased confidence"},{"tag":"Organisational Training","title":"Upskilling an entire independent care provider","story":"An independent complex care provider commissioned bespoke training for 40 staff across three cohorts. CQC inspection following the programme noted \"outstanding\" practice in staff knowledge and family engagement.","outcome":"CQC \"Outstanding\" rating achieved"}]', '2026-05-27 14:50:50', '2026-05-27 14:50:50');
INSERT INTO "page_contents" ("id", "page", "key", "label", "type", "value", "created_at", "updated_at") VALUES (20, 'home', 'about.headline', 'About Block — Headline', 'text', 'Specialists in paediatric complex care education', '2026-05-27 14:50:50', '2026-05-27 14:50:50');
INSERT INTO "page_contents" ("id", "page", "key", "label", "type", "value", "created_at", "updated_at") VALUES (21, 'home', 'about.body1', 'About Block — Paragraph 1', 'textarea', 'MMAB Consulting is a specialist healthcare training consultancy founded by experienced paediatric complex care clinicians. With over a decade of combined NHS and independent sector experience, our team brings unparalleled clinical depth to every programme.', '2026-05-27 14:50:50', '2026-05-27 14:50:50');
INSERT INTO "page_contents" ("id", "page", "key", "label", "type", "value", "created_at", "updated_at") VALUES (22, 'home', 'about.body2', 'About Block — Paragraph 2', 'textarea', 'We deliver training nationwide, working with NHS trusts, independent care providers, and individual healthcare professionals across the UK.', '2026-05-27 14:50:50', '2026-05-27 14:50:50');
INSERT INTO "page_contents" ("id", "page", "key", "label", "type", "value", "created_at", "updated_at") VALUES (23, 'home', 'about.stats', 'About Block — Stats (JSON)', 'json', '[{"value":"10+","label":"Years Experience"},{"value":"500+","label":"Professionals Trained"},{"value":"UK-Wide","label":"Nationwide Delivery"},{"value":"CPD","label":"Accredited Courses"}]', '2026-05-27 14:50:50', '2026-05-27 14:50:50');
INSERT INTO "page_contents" ("id", "page", "key", "label", "type", "value", "created_at", "updated_at") VALUES (24, 'home', 'cta.headline', 'CTA Banner — Headline', 'text', 'Your journey to better care starts here', '2026-05-27 14:50:50', '2026-05-27 14:50:50');
INSERT INTO "page_contents" ("id", "page", "key", "label", "type", "value", "created_at", "updated_at") VALUES (25, 'home', 'cta.subtext', 'CTA Banner — Subtext', 'textarea', 'Speak to our specialist team today and take the first step towards advancing your clinical practice and improving outcomes for the children in your care.', '2026-05-27 14:50:50', '2026-05-27 14:50:50');
INSERT INTO "page_contents" ("id", "page", "key", "label", "type", "value", "created_at", "updated_at") VALUES (26, 'home', 'contact.headline', 'Contact Form — Headline', 'text', 'Get in touch with our team', '2026-05-27 14:50:50', '2026-05-27 14:50:50');
INSERT INTO "page_contents" ("id", "page", "key", "label", "type", "value", "created_at", "updated_at") VALUES (27, 'home', 'contact.subtext', 'Contact Form — Subtext', 'textarea', 'Whether you''re an individual professional or looking to arrange training for your organisation, we''re here to help. Fill in the form and we''ll be in touch within 24 hours.', '2026-05-27 14:50:50', '2026-05-27 14:50:50');
INSERT INTO "page_contents" ("id", "page", "key", "label", "type", "value", "created_at", "updated_at") VALUES (28, 'global', 'site.phone', 'Phone Number', 'text', '+44 (0) 000 000 0000', '2026-05-27 14:50:50', '2026-05-27 14:50:50');
